('cat-12', 'Travel Essentials', 'travel-essentials', 'Designer canvas travel totes, memory foam car seats, and titanium pet strollers.', 'https://images.unsplash.com/photo-1522441815192-d9f04eb0615c?auto=format&fit=crop&q=80&w=800', NOW()),
('cat-13', 'Training Products', 'training-products', 'Luxury leather treat pouches, soft clickers, and visual target mats.', 'https://images.unsplash.com/photo-1537151608828-ea2b117b6281?auto=format&fit=crop&q=80&w=800', NOW()),
('cat-14', 'Luxury Lifestyle', 'luxury-lifestyle', 'Pure Mongolian cashmere pet sweaters, designer housewares, and tailored trench coats.', 'https://images.unsplash.com/photo-1583511655826-05700d52f4d9?auto=format&fit=crop&q=80&w=800', NOW()),
('cat-15', 'Veterinary Wellness', 'veterinary-wellness', 'Complete clinical health packages, geriatric diagnostics support, and DNA screening kits.', 'https://images.unsplash.com/photo-1628009368231-7bb7cfcb0def?auto=format&fit=crop&q=80&w=800', NOW());
INSERT INTO public.products (id, name, slug, description, price, sale_price, stock, category_id, is_featured, rating, created_at, updated_at) VALUES
('prod-1', 'Royal Heritage Bison & Venison Freeze-Dried Loaf', 'royal-heritage-bison-venison-freeze-dried-loaf', 'Uncompromising culinary excellence. Formulated with 95% grass-fed North American bison and wild venison, nutrient-dense organ meats, and organic kelp. Gently freeze-dried to lock in maximum bioavailability.', 5400.00, 4999.00, 24, 'cat-1', true, 4.9, NOW(), NOW()),
('prod-2', 'Artisanal Organic King Salmon & Sweet Potato Kibble', 'artisanal-organic-king-salmon-sweet-potato-kibble', 'Bespoke daily nourishment for the modern companion. Prepared with fresh wild-caught King Salmon, organic sweet potatoes, and rich cold-pressed flaxseed oil to promote a flawless coat.', 3600.00, NULL, 50, 'cat-1', false, 4.8, NOW(), NOW()),
('prod-3', 'Free-Range Wild Boar & Quail Culinary Feast', 'free-range-wild-boar-quail-culinary-feast', 'Premium biological nutrition mimicking ancestral diets. Combines high-protein wild boar and tender quail, cold-pressed prebiotic fibres, and wild-harvested blueberries for cellular wellness.', 4900.00, 4200.00, 30, 'cat-1', true, 5.0, NOW(), NOW()),
('prod-4', 'Gourmet Slow-Simmered Bone Broth Stew (Duck & Herb)', 'gourmet-slow-simmered-bone-broth-stew-duck-herb', 'A rich culinary addition. Slow-cooked duck bone broth infused with organic turmeric, parsley, and tender shredded duck breast. Perfect for joint support and absolute hydration.', 1800.00, NULL, 85, 'cat-1', false, 4.7, NOW(), NOW()),
('prod-5', 'Organic Grass-Fed Beef & Tripe Raw Medallions', 'organic-grass-fed-beef-tripe-raw-medallions', 'Pure freeze-dried raw convenience. Single-source free-range beef muscle and green tripe, bio-active enzymes, and cold-pressed zinc to optimize gut metabolic functions.', 5200.00, 4800.00, 15, 'cat-1', false, 4.9, NOW(), NOW()),
('prod-6', 'Reserve Heritage Lamb & Ancient Grains Recipe', 'reserve-heritage-lamb-ancient-grains-recipe', 'A premium grain-inclusive recipe featuring grass-fed Icelandic lamb, organic pearled barley, and cold-pressed coconut oil. Ideal for pets with sensitive digestive systems.', 4100.00, NULL, 40, 'cat-1', false, 4.6, NOW(), NOW()),
('prod-7', 'Wild-Caught Bluefin Tuna & Caviar Creamy Purée', 'wild-caught-bluefin-tuna-caviar-creamy-pur-e', 'The ultimate luxury cat delicacy. A velvety purée of wild Pacific Bluefin tuna, infused with sustainable sturgeon caviar and essential taurine. Served in elegant single-portion glass jars.', 2800.00, 2499.00, 60, 'cat-2', true, 5.0, NOW(), NOW()),
('prod-8', 'Gourmet Duck Breast & Quail Egg Paté', 'gourmet-duck-breast-quail-egg-pat', 'A rich culinary creation. Premium free-range duck breast blended with whole soft-boiled quail eggs and organic cat grass extracts to prevent hairballs naturally.', 2100.00, NULL, 75, 'cat-2', false, 4.8, NOW(), NOW()),
('prod-9', 'Freeze-Dried Free-Range Pheasant & Venison Bites', 'freeze-dried-free-range-pheasant-venison-bites', 'Ultra-premium high-protein raw nutrition. Formulated with 98% pheasant, venison, and organic pumpkin seeds. Gently freeze-dried to preserve original cellular nutrients.', 3800.00, 3400.00, 35, 'cat-2', true, 4.9, NOW(), NOW()),
('prod-10', 'Ocean Reserve Lobster & Salmon Flakes in Gravy', 'ocean-reserve-lobster-salmon-flakes-in-gravy', 'Fresh Maine lobster claw meat and wild sockeye salmon flakes simmered in rich kelp broth. Provides clean omega fatty acids for an exceptionally glossy coat.', 2900.00, NULL, 45, 'cat-2', false, 4.7, NOW(), NOW()),
('prod-11', 'Organic Rabbit & Cranberry Grain-Free Kibble', 'organic-rabbit-cranberry-grain-free-kibble', 'A boutique recipe featuring organic rabbit meat, cold-pressed botanicals, and wild cranberries. Highly digestible, protecting the delicate feline urinary tract.', 3200.00, 2999.00, 28, 'cat-2', false, 4.9, NOW(), NOW()),
('prod-12', 'Slow-Cooked Heritage Turkey & Catnip Broth', 'slow-cooked-heritage-turkey-catnip-broth', 'Rich free-range turkey bone broth with organic catnip infusion. Stimulates appetite, hydrates felines, and supplies essential collagen molecules.', 1500.00, NULL, 90, 'cat-2', false, 4.6, NOW(), NOW()),
('prod-13', 'Hypoallergenic Hydrolyzed Salmon Formula', 'hypoallergenic-hydrolyzed-salmon-formula', 'Veterinary clinical diet for companions with severe food intolerances. Formulated with hydrolyzed salmon proteins and refined organic starch to prevent inflammatory flare-ups.', 4500.00, 3999.00, 32, 'cat-3', true, 4.8, NOW(), NOW()),
('prod-14', 'Renal Care Low-Phosphorus Organic Chicken Recipe', 'renal-care-low-phosphorus-organic-chicken-recipe', 'Prescription-grade nutrition engineered to support compromise kidney function. Low phosphorus levels combined with controlled premium organic protein structures.', 4800.00, NULL, 20, 'cat-3', false, 4.7, NOW(), NOW()),
('prod-15', 'Low-Glycemic Weight Management Quail Feast', 'low-glycemic-weight-management-quail-feast', 'Clinical formula optimized for pet glucose stability and weight reduction. Features lean quail, prebiotic dietary fibers, and fat-metabolizing L-Carnitine.', 4200.00, 3800.00, 42, 'cat-3', true, 4.9, NOW(), NOW()),
('prod-16', 'Cardiac Support Organic Venison Stew', 'cardiac-support-organic-venison-stew', 'Nutritional therapy with enhanced levels of Taurine, L-Carnitine, and clean wild omega-3 fatty acids to protect heart muscle health and cellular tone.', 5500.00, NULL, 15, 'cat-3', false, 5.0, NOW(), NOW()),
('prod-17', 'Gastrointestinal High-Digestibility Whitefish Recipe', 'gastrointestinal-high-digestibility-whitefish-recipe', 'Clinical veterinary nutrition designed for gastrointestinal soothing. Prepared with pure hydrolyzed cod and prebiotics to restore micobiome equilibrium.', 4300.00, 3999.00, 35, 'cat-3', false, 4.8, NOW(), NOW()),
('prod-18', 'Anallergenic Botanical Insect Protein Formula', 'anallergenic-botanical-insect-protein-formula', 'Cutting-edge clinical veterinary science using highly sustainable, hypoallergenic black soldier fly larvae protein. Zero grain, zero poultry, maximum biological tolerance.', 4900.00, NULL, 18, 'cat-3', false, 4.6, NOW(), NOW()),
('prod-19', 'Apothecary Gold Green-Lipped Mussel Joint Powder', 'apothecary-gold-green-lipped-mussel-joint-powder', 'Highly concentrated joint renewal. Ethically harvested New Zealand green-lipped mussel powder, cold-processed to supply clinical-grade chondroitin and hyaluronic molecules.', 3200.00, 2800.00, 40, 'cat-4', true, 4.9, NOW(), NOW()),
('prod-20', 'Organic Icelandic Wild Kelp Powder', 'organic-icelandic-wild-kelp-powder', 'Cellular vitality supplement sourced from pristine cold ocean trenches. Naturally rich in iodine, iron, and 60+ trace minerals to optimize thyroid and gland metabolic functions.', 1950.00, NULL, 80, 'cat-4', false, 4.8, NOW(), NOW()),
('prod-21', 'Pure Arctic Krill Oil Liposomal Drops', 'pure-arctic-krill-oil-liposomal-drops', 'Unmatched cellular bioavailability. Premium liposomal krill oil extract supplying pure phospholipid-bound omega-3 EPA and DHA, combined with powerful natural astaxanthin.', 3800.00, 3400.00, 25, 'cat-4', true, 5.0, NOW(), NOW()),
('prod-22', 'Holistic Skin & Coat Collagen Elixir', 'holistic-skin-coat-collagen-elixir', 'Nutraceutical liquid collagen booster with biotin and zinc. Promotes rapid hair follicle growth, dermis hydration, and complete nail/claw strengthening.', 2600.00, NULL, 65, 'cat-4', false, 4.7, NOW(), NOW()),
('prod-23', 'Probiotic Shield Multi-Strain Digestive Powder', 'probiotic-shield-multi-strain-digestive-powder', '5 billion CFU active cultures per scoop. Spore-forming probiotics and prebiotics designed to restore microflora, eliminate gas, and improve stool consistency.', 2400.00, 1999.00, 55, 'cat-4', false, 4.9, NOW(), NOW()),
('prod-24', 'Organic Ashwagandha & Valerian Root Calming Oil', 'organic-ashwagandha-valerian-root-calming-oil', 'Bespoke herbal sedative blend to relieve anxiety, stress, and noise fear. Pure botanical extracts blended with premium organic cold-pressed hemp seed oil carriers.', 2900.00, NULL, 50, 'cat-4', false, 4.6, NOW(), NOW()),
('prod-25', 'Silver Shield Colloidal Silver Skin Spray', 'silver-shield-colloidal-silver-skin-spray', 'Pharmaceutical-grade colloidal silver (30 PPM) suspended in purified water. An organic antibacterial and antifungal spray for hot spots, minor cuts, and dermal lesions.', 1800.00, 1599.00, 70, 'cat-5', true, 4.9, NOW(), NOW()),
('prod-26', 'Enzymatic Dental Cleansing Gel (Spearmint & Aloe)', 'enzymatic-dental-cleansing-gel-spearmint-aloe', 'Brushless molecular dental hygiene. Formulated with active enzymes that digest plaque bacteria, combined with organic aloe vera extracts to soothe sensitive gums.', 1400.00, NULL, 90, 'cat-5', false, 4.7, NOW(), NOW()),
('prod-27', 'Apothecary First-Aid Emergency Case (Titanium Edition)', 'apothecary-first-aid-emergency-case-titanium-edition', 'Uncompromising safety on travel. Sleek lightweight case equipped with premium medical scissors, sterile pressure wraps, organic antiseptic salves, and emergency blankets.', 6500.00, 5900.00, 15, 'cat-5', true, 5.0, NOW(), NOW()),
('prod-28', 'Herbal Ear Purifying Drops (Witch Hazel & Tea Tree)', 'herbal-ear-purifying-drops-witch-hazel-tea-tree', 'Clinical ear cleansing drops designed to dissolve accumulated wax and prevent yeast colonies. Formulated with organic witch hazel extracts and calming tea tree oils.', 1250.00, NULL, 110, 'cat-5', false, 4.6, NOW(), NOW()),
('prod-29', 'Organic Cellular Joint Recovery Gel', 'organic-cellular-joint-recovery-gel', 'Topical analgesic massage gel with organic arnica and menthol. Absorbs instantly into skin to reduce muscle tension and soothe arthritis discomfort.', 2200.00, 1899.00, 48, 'cat-5', false, 4.8, NOW(), NOW()),
('prod-30', 'Veterinary Optical Sterility Eye Drops', 'veterinary-optical-sterility-eye-drops', 'Boric-acid-free isotonic saline formula designed to flush foreign matter, soothe allergic irritation, and wash tear-staining patterns safely.', 1100.00, NULL, 130, 'cat-5', false, 4.5, NOW(), NOW()),
('prod-31', 'Royal Cashmere & Silk Coat Wash', 'royal-cashmere-silk-coat-wash', 'Luxurious botanical shampoo infused with genuine hydrolyzed silk proteins, cashmere extracts, and organic rosewater. Ideal for coats needing high-gloss restoration.', 2600.00, 2299.00, 45, 'cat-6', true, 4.9, NOW(), NOW()),
('prod-32', 'Botanical Jasmine Coat De-Tangling Mist', 'botanical-jasmine-coat-de-tangling-mist', 'A light spray formulation containing organic aloe vera, jasmine absolute, and botanical silicones. Safely detangles fine hair without stripping natural lipid layers.', 1800.00, NULL, 65, 'cat-6', false, 4.8, NOW(), NOW()),
('prod-33', 'Organic Shea Butter Paw & Nose Balm', 'organic-shea-butter-paw-nose-balm', 'Healing barrier balm prepared from organic Nilotica shea butter, beeswax, and calendula oils. Soothes cracked paws and dryness caused by hot pavement or cold road salt.', 1500.00, 1290.00, 95, 'cat-6', true, 5.0, NOW(), NOW()),
('prod-34', 'Professional Ergonomic Claw Trimmer (Stainless Steel)', 'professional-ergonomic-claw-trimmer-stainless-steel', 'Surgical-grade stainless steel blades offering precision cuts without crushing the nail. Features an ergonomic wood-handle grip and safety guard.', 2400.00, NULL, 38, 'cat-6', false, 4.7, NOW(), NOW()),
('prod-35', 'Apothecary White Tea & Tea Tree Waterless Foam', 'apothecary-white-tea-tea-tree-waterless-foam', 'Dry cleansing foam with calming organic white tea extract. Neutralizes odours, absorbs dirt particles, and volumizes the coat between wet baths.', 1900.00, 1699.00, 55, 'cat-6', false, 4.8, NOW(), NOW()),
('prod-36', 'Boar Bristle Hand-Polished Coat Brush', 'boar-bristle-hand-polished-coat-brush', 'Bespoke beechwood paddle brush set with 100% natural boar bristles. Distributes the skin''s natural sebum throughout the coat fibers for a radiant polish.', 3800.00, NULL, 20, 'cat-6', false, 5.0, NOW(), NOW()),
('prod-37', 'Italian Leather Hand-Braided Fetch Ring', 'italian-leather-hand-braided-fetch-ring', 'Elegant utility at the park. Hand-braided from vegetable-tanned Italian leather with reinforced internal core. Soft on your companion''s jaw and extremely durable.', 3400.00, 2999.00, 25, 'cat-7', true, 4.9, NOW(), NOW()),
('prod-38', 'Natural Organic Rubber Treat Dispenser Cube', 'natural-organic-rubber-treat-dispenser-cube', 'Designer heavy-duty rubber chew toy with irregular geometric bounce. Internal puzzle chambers holds freeze-dried rewards to stimulate cognitive thinking.', 2200.00, NULL, 60, 'cat-7', false, 4.8, NOW(), NOW()),
('prod-39', 'Bespoke Belgian Linen Squeaker Bone', 'bespoke-belgian-linen-squeaker-bone', 'Minimalist dog toy crafted from heavy Belgian performance linen and stuffed with organic cotton. Safe non-toxic internal squeaker provides rich auditory play.', 1800.00, 1499.00, 80, 'cat-7', true, 4.7, NOW(), NOW()),
('prod-40', 'Smart Treat Maze Interactive Puzzle (Level 3)', 'smart-treat-maze-interactive-puzzle-level-3', 'Luxury wooden interactive console designed to challenge your companion''s problem-solving skills. Slide columns and lift blocks to find hidden treats.', 5800.00, NULL, 15, 'cat-7', false, 5.0, NOW(), NOW()),
('prod-41', 'Organic Cotton Braided Anchor Tug', 'organic-cotton-braided-anchor-tug', 'Extra-thick non-toxic organic cotton fibers tightly braided to support extreme tugging and jaw play. Promotes dental cleaning naturally via fiber flossing.', 1600.00, NULL, 100, 'cat-7', false, 4.6, NOW(), NOW()),
('prod-42', 'Bespoke Wool Felt Interactive Snuffle Mat', 'bespoke-wool-felt-interactive-snuffle-mat', 'Handcrafted felt mat with layers of hiding pockets. Distribute freeze-dried lamb treats to activate natural scent tracking instincts.', 2900.00, 2600.00, 40, 'cat-7', false, 4.9, NOW(), NOW()),
('prod-43', 'Tuscan Leather Gilded Collar', 'tuscan-leather-gilded-collar', 'Exquisite hand-stitched collar made from full-grain vegetable-tanned Tuscan leather. Features solid brass hardware electroplated in 24k gold, reinforced stitching, and a soft nubuck leather inner lining.', 6200.00, 5800.00, 18, 'cat-8', true, 4.9, NOW(), NOW()),
('prod-44', 'Saddle Leather Braided Luxury Lead', 'saddle-leather-braided-luxury-lead', 'Elegant control at your side. Craft from robust English saddle leather with hand-finished round stitching and a solid gold-toned security swivel hook.', 7800.00, NULL, 22, 'cat-8', false, 4.8, NOW(), NOW()),
('prod-45', 'Handcrafted Brass Identification Medallion', 'handcrafted-brass-identification-medallion', 'Bespoke raw brass tag hand-engraved with client coordinates. Patinas beautifully over time, providing classic historical styling.', 1900.00, 1599.00, 120, 'cat-8', true, 5.0, NOW(), NOW()),
('prod-46', 'Silk Twill Equestrian Dog Bandana', 'silk-twill-equestrian-dog-bandana', 'Stunning 100% silk twill bandana featuring hand-rolled edges and a custom heritage equestrian print pattern. Soft, light, and hyper-elegant.', 4500.00, NULL, 30, 'cat-8', false, 4.7, NOW(), NOW()),
('prod-47', 'Nappa Leather Bow Tie Collar Attachment', 'nappa-leather-bow-tie-collar-attachment', 'Classic tuxedo style for formal events. Soft padded black Nappa leather bow tie featuring a rear elastic band to slip easily onto existing collars.', 2800.00, 2490.00, 40, 'cat-8', false, 4.9, NOW(), NOW()),
('prod-48', 'Heritage Tweed Walking Harness', 'heritage-tweed-walking-harness', 'Timeless British country style. Tailored from robust Harris Tweed, reinforced with nylon interior webbing and golden quick-release security clips.', 5600.00, NULL, 25, 'cat-8', false, 4.8, NOW(), NOW()),
('prod-49', 'Royal Velvet Orthopedic Bed', 'royal-velvet-orthopedic-bed', 'Indulge your companion with the absolute height of comfort. Crafted with three layers of high-density orthopedic memory foam, wrapped in an ultra-soft, stain-resistant royal velvet cover.', 12500.00, 10999.00, 12, 'cat-9', true, 4.9, NOW(), NOW()),
('prod-50', 'Bespoke Oak Indoor Slatted Den', 'bespoke-oak-indoor-slatted-den', 'A sanctuary for your companion that doubles as an elegant side table for your living room. Handcrafted from sustainably-sourced premium white oak with a oil finish.', 45000.00, 42000.00, 3, 'cat-9', true, 5.0, NOW(), NOW()),
('prod-51', 'Pure Mongolian Cashmere Cozy Blanket', 'pure-mongolian-cashmere-cozy-blanket', 'Wrap your pet in unparalleled luxury. Woven from 100% grade-A cashmere fibers. Unbelievably soft, providing warm cellular insulation on cold evenings.', 14500.00, 12999.00, 10, 'cat-9', true, 5.0, NOW(), NOW()),
('prod-52', 'Belgian Linen Padded Nest Bed', 'belgian-linen-padded-nest-bed', 'Understated organic style. Heavy-weave Belgian linen stuffed with hypoallergenic organic cotton fluff. Ideal for summer resting and modern minimal environments.', 9800.00, NULL, 18, 'cat-9', false, 4.8, NOW(), NOW()),
('prod-53', 'Orthopedic Bolster Bed in Charcoal Bouclé', 'orthopedic-bolster-bed-in-charcoal-boucl', 'Premium memory foam mattress with raised padded borders to support the neck. Covered in a thick, textured charcoal bouclé fabric that resists claw scratching.', 11500.00, 9999.00, 14, 'cat-9', false, 4.9, NOW(), NOW()),
('prod-54', 'Ergonomic Nesting Pet Pod (Sleek Felt)', 'ergonomic-nesting-pet-pod-sleek-felt', 'Modern cocoon den molded from high-density compression felt. Fits smaller dogs and cats, shielding them to provide secure, deep sleep cycles.', 6800.00, NULL, 20, 'cat-9', false, 4.7, NOW(), NOW()),
('prod-55', 'Carrara Marble Double Pet Dining Set', 'carrara-marble-double-pet-dining-set', 'Stunning elevated feeding table hand-carved from a single block of polished Italian Carrara marble. Features two removable gold-electroplated stainless steel bowls.', 18000.00, 15999.00, 8, 'cat-10', true, 5.0, NOW(), NOW()),
('prod-56', 'Hand-Hammered Solid Brass Single Bowl', 'hand-hammered-solid-brass-single-bowl', 'Artisanal tabletop bowl hand-hammered from solid heavy-gauge brass. Coated with food-safe protective lacquer. Anti-skid rubber base rings prevent floor sliding.', 3400.00, NULL, 40, 'cat-10', false, 4.8, NOW(), NOW()),
('prod-57', 'Slow-Feeder Ceramic Wave Plate', 'slow-feeder-ceramic-wave-plate', 'Feed slowly with sophisticated form. High-fire stoneware ceramic featuring organic wave ripples that force companions to eat pace-by-pace, reducing bloating.', 2900.00, 2490.00, 35, 'cat-10', true, 4.9, NOW(), NOW()),
('prod-58', 'Luxury Elevated Walnut Dining Stand', 'luxury-elevated-walnut-dining-stand', 'Double feeder stand crafted from solid walnut wood. Elevates bowls by 8 inches to relieve neck and spinal strain on larger breeds during feeding.', 8800.00, NULL, 15, 'cat-10', false, 4.8, NOW(), NOW()),
('prod-59', 'Travel Food Container in Sage Silicone', 'travel-food-container-in-sage-silicone', 'Collapsible, food-safe silicone travel canister with airtight wood lid. Easily holds up to 1.5kg of kibble during road trips and premium weekends.', 2100.00, 1800.00, 55, 'cat-10', false, 4.7, NOW(), NOW()),
('prod-60', 'Pure Copper Water Fountain (Silent Pump)', 'pure-copper-water-fountain-silent-pump', 'Continuous fresh oxygenated hydration. Spun solid copper bowl featuring a silent charcoal filtration pump, generating a flowing, pure aquatic soundscape.', 12500.00, NULL, 12, 'cat-10', false, 4.9, NOW(), NOW()),
('prod-61', 'Antibacterial Silk Wet Wipes (Coconut Oil)', 'antibacterial-silk-wet-wipes-coconut-oil', 'Apothecary-grade clinical wet wipes. Infused with organic coconut oil, colloidal silver, and silk amino acids. Sanitizes paws and coat while restoring cellular moisture.', 1100.00, 950.00, 150, 'cat-11', true, 4.9, NOW(), NOW()),
('prod-62', 'Self-Cleaning Smart Litter Pod', 'self-cleaning-smart-litter-pod', 'High-tech feline waste automation. Uses whisper-silent rotation to separate waste, logging cat entry cycles on a secure app. Enclosed carbon-filter eliminates odors.', 32000.00, 28999.00, 10, 'cat-11', true, 4.8, NOW(), NOW()),
('prod-63', 'Bio-Degradable Lavender Waste Bags (12 Rolls)', 'bio-degradable-lavender-waste-bags-12-rolls', 'Eco-conscious design. Extra-thick cornstarch compostable waste bags infused with natural lavender oils. Leak-proof structure ensures secure transport.', 900.00, NULL, 200, 'cat-11', false, 4.8, NOW(), NOW()),
('prod-64', 'Enzymatic Odour Eliminator & Urised Mist', 'enzymatic-odour-eliminator-urised-mist', 'A powerful bio-enzymatic spray that targets urine and waste molecules, destroying them at the cellular level. Leaves a crisp herbal lime scent.', 1500.00, NULL, 90, 'cat-11', false, 4.7, NOW(), NOW()),
('prod-65', 'Premium Bamboo Charcoal Training Pads', 'premium-bamboo-charcoal-training-pads', 'Ultra-absorbent training pads containing natural bamboo charcoal. Instantly locks in moisture and neutralizes ammonia odors, keeping flooring dry.', 1900.00, 1699.00, 80, 'cat-11', false, 4.8, NOW(), NOW()),
('prod-66', 'Eucalyptus Dry Pet Cologne Spray', 'eucalyptus-dry-pet-cologne-spray', 'A botanical daily refresh spray. Infused with pure organic eucalyptus oils, cedarwood extracts, and natural alcohol-free neutralizers to combat coat odour.', 1600.00, NULL, 110, 'cat-11', false, 4.6, NOW(), NOW()),
('prod-67', 'Designer Canvas & Tuscan Leather Carrier', 'designer-canvas-tuscan-leather-carrier', 'The epitome of elite travel style. Sturdy organic cotton canvas reinforced with vegetable-tanned Tuscan leather trim. Features mesh ventilation and cozy internal pad.', 18500.00, 16900.00, 12, 'cat-12', true, 5.0, NOW(), NOW()),
('prod-68', 'Isofix Memory Foam Car Safety Seat', 'isofix-memory-foam-car-safety-seat', 'Secure protection on the highway. Securely attaches using Isofix hooks, featuring high-density memory foam padding and internal security leash links.', 9200.00, NULL, 15, 'cat-12', false, 4.9, NOW(), NOW()),
('prod-69', 'Aerospace Aluminium Pet Stroller', 'aerospace-aluminium-pet-stroller', 'Elegant mobile suspension. Fabricated with lightweight aerospace-grade aluminium frame, flat-fold mechanism, and premium wear-resistant rubber tyres.', 28500.00, 26000.00, 6, 'cat-12', true, 4.9, NOW(), NOW()),
('prod-70', 'Stainless Steel Insulated Travel Flask', 'stainless-steel-insulated-travel-flask', 'Keep water ice-cold for 24 hours. Double-wall vacuum insulated flask featuring a fold-out silicone leaf bowl for easy drinking access during treks.', 2400.00, NULL, 70, 'cat-12', false, 4.8, NOW(), NOW()),
('prod-71', 'Waterproof Quilted Seat Protection Cover', 'waterproof-quilted-seat-protection-cover', 'Heavy-duty 4-layer quilted Oxford fabric hammock that covers the rear car seats completely. Resists claws, mud, water, and pet dander.', 4800.00, 4200.00, 35, 'cat-12', false, 4.7, NOW(), NOW()),
('prod-72', 'Bespoke Leather Passport & Health Record Wallet', 'bespoke-leather-passport-health-record-wallet', 'Keep documentation organized. Sleek wallet handcrafted from calfskin leather to hold vet files, vaccine history logs, and pet travel passports.', 3800.00, NULL, 40, 'cat-12', false, 5.0, NOW(), NOW()),
('prod-73', 'Premium Calfskin Treat Bag (Magnetic Closure)', 'premium-calfskin-treat-bag-magnetic-closure', 'Stylish training accessory. Handcrafted from waterproof calfskin leather with a quick-access magnetic snap closure. Easily clips to belts or shoulder straps.', 3600.00, 3200.00, 40, 'cat-13', true, 4.9, NOW(), NOW()),
('prod-74', 'Professional Silent Training Whistle (Solid Silver)', 'professional-silent-training-whistle-solid-silver', 'Elite acoustic design. Precision machined from solid sterling silver. Features micro-adjustable pitch control to lock in perfect recall frequencies.', 4900.00, NULL, 25, 'cat-13', false, 5.0, NOW(), NOW()),
('prod-75', 'Organic Cork Recall Training Mat', 'organic-cork-recall-training-mat', 'Establish visual targeting boundaries. Molded from 100% natural, antimicrobial organic cork sheet. Non-slip backing ensures absolute floor stability.', 2800.00, 2400.00, 50, 'cat-13', true, 4.8, NOW(), NOW()),
('prod-76', 'Leather Recall Lead (30 Feet Longline)', 'leather-recall-lead-30-feet-longline', 'Extra-long recall lead crafted from raw-cut harness leather. Lightweight yet holds up to 150kg of tension. Perfect for advanced distance commands.', 4500.00, NULL, 30, 'cat-13', false, 4.7, NOW(), NOW()),
('prod-77', 'Ergonomic Wood-Finish Clicker Kit (2 Pack)', 'ergonomic-wood-finish-clicker-kit-2-pack', 'Precision conditioning clicks. Hand-polished rosewood and maple shell clickers supplying crisp, clear sounds to mark positive behaviours.', 1500.00, 1200.00, 85, 'cat-13', false, 4.6, NOW(), NOW()),
('prod-78', 'Natural Scent-Tracking Diagnostic Training kit', 'natural-scent-tracking-diagnostic-training-kit', 'Activate natural olfactory capabilities. Includes target scent bottles (lavender, pine, anise) and organic target canisters for scent tracking.', 3400.00, NULL, 20, 'cat-13', false, 4.9, NOW(), NOW()),
('prod-79', 'Pure Cashmere Pet Sweater (Mongolian Cable)', 'pure-cashmere-pet-sweater-mongolian-cable', 'Keep your pet elegant and warm in chilly seasons. Woven from 100% genuine Grade-A Mongolian cashmere, featuring a classic British cable-knit pattern.', 8500.00, NULL, 15, 'cat-14', true, 4.8, NOW(), NOW()),
('prod-80', 'Minimalist Walnut Pet Stairs (Velvet Steps)', 'minimalist-walnut-pet-stairs-velvet-steps', 'Bespoke steps carved from rich American walnut wood, covered in plush velvet. Helps older companions mount higher couches and beds with dignity.', 18500.00, 16999.00, 5, 'cat-14', true, 4.9, NOW(), NOW()),
('prod-81', 'Artisanal Brass & Oak Pet Umbrella', 'artisanal-brass-oak-pet-umbrella', 'Premium rain protection during walks. Constructed with a solid white oak handle, polished brass ribbing, and thick waterproof nylon canopy.', 9500.00, 7900.00, 8, 'cat-14', true, 5.0, NOW(), NOW()),
('prod-82', 'Bespoke Organic Silk Night Robe', 'bespoke-organic-silk-night-robe', 'Plush evening robe constructed from 100% natural Mulberry silk with waist sash tie. Designed for sensory relaxation after botanical baths.', 7200.00, NULL, 18, 'cat-14', false, 4.7, NOW(), NOW()),
('prod-83', 'Gold-Plated Designer Identification Chain', 'gold-plated-designer-identification-chain', 'A statement fashion chain electroplated in heavy 18k gold. Designed for light social events and elegant editorial photo captures.', 5400.00, 4800.00, 25, 'cat-14', false, 4.9, NOW(), NOW()),
('prod-84', 'Designer Cotton Trench Coat (Double-Breasted)', 'designer-cotton-trench-coat-double-breasted', 'Iconic classic silhouette double-breasted trench. Tailored from water-repellent organic cotton gabardine, featuring a checked internal cotton lining.', 11000.00, NULL, 12, 'cat-14', false, 4.8, NOW(), NOW()),
('prod-85', 'Advanced DNA Screening & Breed Ancestry Kit', 'advanced-dna-screening-breed-ancestry-kit', 'Decode your companion''s genetic code. Analyzes 350+ dog breeds, screens for 200+ genetic health risks, and provides complete ancestral family reports.', 9900.00, 8900.00, 45, 'cat-15', true, 5.0, NOW(), NOW()),
('prod-86', 'Comprehensive Geriatric Metabolic Health Package', 'comprehensive-geriatric-metabolic-health-package', 'Complete at-home specimen collection kit. Validates liver, kidney, glucose, and thyroid panels at our partner laboratories in Shivamogga.', 12000.00, NULL, 30, 'cat-15', false, 4.9, NOW(), NOW()),
('prod-87', 'Bio-Active Gut Microbiome DNA Diagnostics Kit', 'bio-active-gut-microbiome-dna-diagnostics-kit', 'Unlock optimal digestion. Analyzes the gut bacterial species mapping, supplying tailored probiotic recipes and clinical dietary suggestions.', 7500.00, 6800.00, 50, 'cat-15', true, 4.8, NOW(), NOW()),
('prod-88', 'Heavy Metals & Cellular Toxin Screening Kit', 'heavy-metals-cellular-toxin-screening-kit', 'Screens hair/saliva samples for toxic contamination, heavy metals, or pesticide exposures, providing veterinary detoxification guidelines.', 6400.00, NULL, 25, 'cat-15', false, 4.7, NOW(), NOW()),
('prod-89', 'Allergen Panel Testing Kit (60 Environmental Triggers)', 'allergen-panel-testing-kit-60-environmental-triggers', 'Clinical screening for 60 pollen, food, and environmental triggers causing chronic hot spots. Diagnostic processed by board-certified veterinarians.', 8900.00, 7990.00, 35, 'cat-15', false, 4.9, NOW(), NOW()),
('prod-90', 'At-Home Urinalysis & Kidney Diagnostic Strips', 'at-home-urinalysis-kidney-diagnostic-strips', 'Simple diagnostic strip set with card reader app. Monitors protein, pH, glucose, and ketones to track early signs of kidney issues.', 2200.00, NULL, 120, 'cat-15', false, 4.6, NOW(), NOW());
